mapper.select:
		SELECT
			k.*
		FROM (

			SELECT
				T${idx}._id,
				#{id} childId,
				T${idx}.lvl level
			FROM
				(
					SELECT
						@r${idx} AS _id,
						(
							SELECT
								@r${idx} := parent_id
							FROM
                                skyeye_catalog
							WHERE id = _id

                                AND tenant_id = #{tenantId}

							LIMIT 1
						) AS parent_id,
						@l${idx} := @l${idx} + 1 AS lvl
					FROM
					(
						SELECT
							@r${idx} := #{id},
							@l${idx} := 0
						) vars,
                        skyeye_catalog h
					WHERE @r${idx} != '0'

                        AND h.tenant_id = #{tenantId}

				) T${idx}
		) k

select.foreach:
SELECT
    d.id
FROM
    (
        SELECT
            @ids${idx} AS _ids,
            (
                SELECT
                    @ids${idx} := GROUP_CONCAT(id)
                FROM
                    skyeye_catalog
                WHERE FIND_IN_SET(parent_id, @ids${idx})

                    AND tenant_id = #{tenantId}

            ) AS cids,
            @l${idx} := @l${idx} + 1 AS level
        FROM
            skyeye_catalog,
            (
                SELECT
                    @ids${idx} := #{id},
                    @l${idx} := 0
            ) b
        WHERE @ids${idx} IS NOT NULL

            AND tenant_id = #{tenantId}

    ) i,
    skyeye_catalog d
WHERE FIND_IN_SET(d.id, i._ids)

    AND d.tenant_id = #{tenantId}
